INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('ABS-01', 'hard', 'category_1_absolute_block', 'CRICOS 미등록 학교 차단', 'Condition: 추천 학교가 CRICOS 등록 안 된 경우 | Action: ❌ 추천 제외 (학생비자 발급 불가) | Alternative: ✅ CRICOS 등록 학교만 추천 | Wilson 19년: CRICOS = 호주 정부 등록 외국학생 교육기관 코드. 미등록 = 학생비자 자체 불가', '{"rule_name": "CRICOS 미등록 학교 차단", "condition": "추천 학교가 CRICOS 등록 안 된 경우", "action": "❌ 추천 제외 (학생비자 발급 불가)", "alternative": "✅ CRICOS 등록 학교만 추천", "wilson_reason": "CRICOS = 호주 정부 등록 외국학생 교육기관 코드. 미등록 = 학생비자 자체 불가", "origin": "ChatGPT 신규", "priority": "절대"}'::jsonb, '❌ 추천 제외 (학생비자 발급 불가)', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('ABS-02', 'hard', 'category_1_absolute_block', '온라인-only 과정 차단', 'Condition: 100% 온라인 과정 추천 시도 | Action: ❌ 학생비자 목적 불가 | Alternative: ✅ Face-to-face 또는 Hybrid (대면 33%+ 필수) | Wilson 19년: DHA 학생비자 = 대면 교육 33% 이상 필수. 온라인-only = 비자 발급 X', '{"rule_name": "온라인-only 과정 차단", "condition": "100% 온라인 과정 추천 시도", "action": "❌ 학생비자 목적 불가", "alternative": "✅ Face-to-face 또는 Hybrid (대면 33%+ 필수)", "wilson_reason": "DHA 학생비자 = 대면 교육 33% 이상 필수. 온라인-only = 비자 발급 X", "origin": "ChatGPT 신규", "priority": "절대"}'::jsonb, '❌ 학생비자 목적 불가', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('ABS-03', 'hard', 'category_1_absolute_block', '초기 학비 납입 불가 차단', 'Condition: 초기 학비 (보통 1학기) 납입 능력 없음 | Action: ❌ COE 발급 불가 = 비자 신청 불가 | Alternative: ✅ 가성비 코스 (Cat 3 / TAFE) + 분할 납부 학교 추천 | Wilson 19년: COE (Confirmation of Enrolment) = 학비 선납 후 발급. 납입 불가 = 비자 신청 자체 불가능', '{"rule_name": "초기 학비 납입 불가 차단", "condition": "초기 학비 (보통 1학기) 납입 능력 없음", "action": "❌ COE 발급 불가 = 비자 신청 불가", "alternative": "✅ 가성비 코스 (Cat 3 / TAFE) + 분할 납부 학교 추천", "wilson_reason": "COE (Confirmation of Enrolment) = 학비 선납 후 발급. 납입 불가 = 비자 신청 자체 불가능", "origin": "ChatGPT 신규", "priority": "절대"}'::jsonb, '❌ COE 발급 불가 = 비자 신청 불가', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('ABS-04', 'hard', 'category_1_absolute_block', '비자 거절 이력 + 사유 불명 차단', 'Condition: 이전 호주 비자 거절 이력 + 거절 사유 정확히 모름 | Action: ❌ 즉시 추천 차단 → 이민 변호사 상담 필수 | Alternative: ✅ 거절 사유 파악 → 사유서 보강 → 재신청 전략 | Wilson 19년: 비자 거절 이력 = 재신청 매우 어려움. 사유 모르고 진행 = 또 거절 + 시간/돈 손실', '{"rule_name": "비자 거절 이력 + 사유 불명 차단", "condition": "이전 호주 비자 거절 이력 + 거절 사유 정확히 모름", "action": "❌ 즉시 추천 차단 → 이민 변호사 상담 필수", "alternative": "✅ 거절 사유 파악 → 사유서 보강 → 재신청 전략", "wilson_reason": "비자 거절 이력 = 재신청 매우 어려움. 사유 모르고 진행 = 또 거절 + 시간/돈 손실", "origin": "ChatGPT 신규 + 윌슨 페르소나 차단룰 통합", "priority": "절대"}'::jsonb, '❌ 즉시 추천 차단 → 이민 변호사 상담 필수', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('ABS-05', 'hard', 'category_1_absolute_block', 'EC English / Embassy / IH Sydney / 폐교 18곳 차단', 'Condition: 어학원 추천 시 18개 폐교 학교 포함 | Action: ❌ 절대 추천 X | Alternative: ✅ 운영 중인 어학원 47개 풀 중 추천 | Wilson 19년: EC English (2021 호주 폐교) / Embassy (EC 자매 폐교) / IH Sydney (2024.12.09 영구 폐교) 외 SELC, Lonsdale, ITHEA, UPC, Einstein, Astley, RGIT, Business Institute, Cocoon, Perth ICE, Language Academy, Leeds, Lloyds 등 18곳. 다른 유학원 아직도 SELC 추천 中 ⚠️', '{"rule_name": "EC English / Embassy / IH Sydney / 폐교 18곳 차단", "condition": "어학원 추천 시 18개 폐교 학교 포함", "action": "❌ 절대 추천 X", "alternative": "✅ 운영 중인 어학원 47개 풀 중 추천", "wilson_reason": "EC English (2021 호주 폐교) / Embassy (EC 자매 폐교) / IH Sydney (2024.12.09 영구 폐교) 외 SELC, Lonsdale, ITHEA, UPC, Einstein, Astley, RGIT, Business Institute, Cocoon, Perth ICE, Language Academy, Leeds, Lloyds 등 18곳. 다른 유학원 아직도 SELC 추천 中 ⚠️", "origin": "윌슨 BLOCK-013 + 19년 직접 검증", "priority": "절대"}'::jsonb, '❌ 절대 추천 X', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('GS-01', 'hard', 'category_2_gs_core', '전공 변경 + 이유 없음', 'Condition: 이전 학력/직업 ≠ 새 전공 + 변경 이유 설명 없음 | Action: 🔴 GS 평가 BLOCK 위험 | Alternative: ✅ 전공 변경 사유서 작성 + 커리어 연결성 명확화 | Wilson 19년: DHA = 전공 변경 시 학업 목적/커리어 연결 평가. 이유 없으면 = 학업 목적 불명확 = GS 거절', '{"rule_name": "전공 변경 + 이유 없음", "condition": "이전 학력/직업 ≠ 새 전공 + 변경 이유 설명 없음", "action": "🔴 GS 평가 BLOCK 위험", "alternative": "✅ 전공 변경 사유서 작성 + 커리어 연결성 명확화", "wilson_reason": "DHA = 전공 변경 시 학업 목적/커리어 연결 평가. 이유 없으면 = 학업 목적 불명확 = GS 거절", "origin": "ChatGPT 신규 2026 핵심", "priority": "🔴 매우 높음"}'::jsonb, '🔴 GS 평가 BLOCK 위험', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('GS-02', 'hard', 'category_2_gs_core', '학업 공백 3년+ 설명 없음', 'Condition: 최종 학력 또는 마지막 학업 종료 후 3년+ 공백 + 설명 없음 | Action: 🔴 GS 평가 BLOCK 위험 | Alternative: ✅ 공백 기간 활동 (직장/사업/육아 등) + 다시 공부하는 이유 명확화 | Wilson 19년: DHA = 학업 공백 = 학업 동기 약함으로 판단. 3년+ = 강한 설명 필요. 한국 고졸 후 30대 = 위험', '{"rule_name": "학업 공백 3년+ 설명 없음", "condition": "최종 학력 또는 마지막 학업 종료 후 3년+ 공백 + 설명 없음", "action": "🔴 GS 평가 BLOCK 위험", "alternative": "✅ 공백 기간 활동 (직장/사업/육아 등) + 다시 공부하는 이유 명확화", "wilson_reason": "DHA = 학업 공백 = 학업 동기 약함으로 판단. 3년+ = 강한 설명 필요. 한국 고졸 후 30대 = 위험", "origin": "ChatGPT 신규 2026 핵심", "priority": "🔴 매우 높음"}'::jsonb, '🔴 GS 평가 BLOCK 위험', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('GS-03', 'hard', 'category_2_gs_core', '고학력 → 낮은 과정 (다운그레이드)', 'Condition: 이미 학사 보유 + 호주에서 Diploma/Cert 지원 (다운그레이드) | Action: 🔴 GS 평가 BLOCK 위험 | Alternative: ✅ 같은 또는 높은 레벨 (Master) 또는 명확한 PR 목적/직업 전환 사유 | Wilson 19년: DHA = 다운그레이드 = ''비자 목적 의심'' 신호. PR 목적이라면 PR 경로 명확히 설명 필수 (TAFE 트레이드 PR 95% 등)', '{"rule_name": "고학력 → 낮은 과정 (다운그레이드)", "condition": "이미 학사 보유 + 호주에서 Diploma/Cert 지원 (다운그레이드)", "action": "🔴 GS 평가 BLOCK 위험", "alternative": "✅ 같은 또는 높은 레벨 (Master) 또는 명확한 PR 목적/직업 전환 사유", "wilson_reason": "DHA = 다운그레이드 = ''비자 목적 의심'' 신호. PR 목적이라면 PR 경로 명확히 설명 필수 (TAFE 트레이드 PR 95% 등)", "origin": "ChatGPT 신규 2026 핵심", "priority": "🔴 매우 높음"}'::jsonb, '🔴 GS 평가 BLOCK 위험', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('GS-04', 'hard', 'category_2_gs_core', 'GS 거절 위험 워홀러', 'Condition: 워홀 1년+ + 영어 낮음 + 학력/경력 X + 학생비자 전환 시도 | Action: 🔴 GS 거절 가능성 매우 높음 | Alternative: ✅ 워홀 직종 = PR 경력 카운트 가능한 직종 매칭 + 학업 연결 명확화 + 사유서 보강 | Wilson 19년: 윌슨 19년 = 워홀 후 학업 연결 없으면 GS 거절 多. : 워홀 직종 → PR 경력 카운트 → 학업 연결 = 강한 GS', '{"rule_name": "GS 거절 위험 워홀러", "condition": "워홀 1년+ + 영어 낮음 + 학력/경력 X + 학생비자 전환 시도", "action": "🔴 GS 거절 가능성 매우 높음", "alternative": "✅ 워홀 직종 = PR 경력 카운트 가능한 직종 매칭 + 학업 연결 명확화 + 사유서 보강", "wilson_reason": "윌슨 19년 = 워홀 후 학업 연결 없으면 GS 거절 多. : 워홀 직종 → PR 경력 카운트 → 학업 연결 = 강한 GS", "origin": "윌슨 BLOCK-023 + ChatGPT GS-04 통합", "priority": "🔴 매우 높음"}'::jsonb, '🔴 GS 거절 가능성 매우 높음', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('GS-05', 'hard', 'category_2_gs_core', '관광비자 → 학생비자 전환', 'Condition: 관광비자 (600/651) 입국 후 학생비자 전환 시도 | Action: 🔴 GS 평가 매우 엄격 | Alternative: ✅ 한국 귀국 후 학생비자 신청 + 사유서 보강 | Wilson 19년: DHA = 관광 → 학생비자 전환 = ''비자 쇼핑'' 의심. GS 평가 매우 까다로움. 한국 귀국 후 신청이 안전', '{"rule_name": "관광비자 → 학생비자 전환", "condition": "관광비자 (600/651) 입국 후 학생비자 전환 시도", "action": "🔴 GS 평가 매우 엄격", "alternative": "✅ 한국 귀국 후 학생비자 신청 + 사유서 보강", "wilson_reason": "DHA = 관광 → 학생비자 전환 = ''비자 쇼핑'' 의심. GS 평가 매우 까다로움. 한국 귀국 후 신청이 안전", "origin": "ChatGPT 신규", "priority": "🔴 매우 높음"}'::jsonb, '🔴 GS 평가 매우 엄격', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('GS-06', 'hard', 'category_2_gs_core', '잦은 코스 변경', 'Condition: 호주 도착 후 코스 2회+ 변경 이력 | Action: 🔴 다음 비자 GS 평가 위험 | Alternative: ✅ 코스 변경 사유 일관성 있게 설명 + 커리어 연결 | Wilson 19년: DHA = 코스 잦은 변경 = 학업 목적 불명확. 추천 시 학생에게 ''이번이 마지막 변경'' 명확히 인지시킴', '{"rule_name": "잦은 코스 변경", "condition": "호주 도착 후 코스 2회+ 변경 이력", "action": "🔴 다음 비자 GS 평가 위험", "alternative": "✅ 코스 변경 사유 일관성 있게 설명 + 커리어 연결", "wilson_reason": "DHA = 코스 잦은 변경 = 학업 목적 불명확. 추천 시 학생에게 ''이번이 마지막 변경'' 명확히 인지시킴", "origin": "ChatGPT 신규", "priority": "🔴 높음"}'::jsonb, '🔴 다음 비자 GS 평가 위험', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('GS-07', 'hard', 'category_2_gs_core', '단순 비자 연장 + 사파 학교 고집', 'Condition: 워홀러 비자 연장 목적 + 학업 의지 0% + 저가/사파 학교 고집 | Action: 🔴 GS 거절 + 폐교 위험 동시 | Alternative: ✅ 학업 의지 점검 + 운영 안전한 가성비 학교 추천 | Wilson 19년: 윌슨 19년 = 단순 비자 연장 + 사파 학교 = 학교 폐교 시 비자 영향 + GS 의심 동시. B2 페르소나 핵심 차단', '{"rule_name": "단순 비자 연장 + 사파 학교 고집", "condition": "워홀러 비자 연장 목적 + 학업 의지 0% + 저가/사파 학교 고집", "action": "🔴 GS 거절 + 폐교 위험 동시", "alternative": "✅ 학업 의지 점검 + 운영 안전한 가성비 학교 추천", "wilson_reason": "윌슨 19년 = 단순 비자 연장 + 사파 학교 = 학교 폐교 시 비자 영향 + GS 의심 동시. B2 페르소나 핵심 차단", "origin": "윌슨 BLOCK-024", "priority": "🔴 높음"}'::jsonb, '🔴 GS 거절 + 폐교 위험 동시', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('DIR-01', 'soft', 'category_3_direct_entry_block', '영어 부족 + 학부 직접 차단', 'Condition: IELTS < 5.5 또는 영어 시험 없음 + 학부/석사 Direct 지원 | Action: ❌ Direct 차단 | Alternative: ✅ 어학원 (필리핀 EC → 호주 EAP) → Foundation/Diploma → 학부 | Wilson 19년: 영어 부족 = 호주 도착 후 학업 따라가기 불가능 = 가장 큰 실패 케이스 (윌슨 19년 실패)', '{"rule_name": "영어 부족 + 학부 직접 차단", "condition": "IELTS < 5.5 또는 영어 시험 없음 + 학부/석사 Direct 지원", "action": "❌ Direct 차단", "alternative": "✅ 어학원 (필리핀 EC → 호주 EAP) → Foundation/Diploma → 학부", "wilson_reason": "영어 부족 = 호주 도착 후 학업 따라가기 불가능 = 가장 큰 실패 케이스 (윌슨 19년 실패)", "origin": "윌슨 BLOCK-001 + ChatGPT DIR-01/DIR-02 통합", "priority": "높음"}'::jsonb, '❌ Direct 차단', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('DIR-02', 'soft', 'category_3_direct_entry_block', '고졸 + 석사 직접 차단', 'Condition: 한국 학력 = 고졸 (검정고시/수능/내신) + 호주 석사 Direct 지원 | Action: ❌ 석사 Direct 차단 | Alternative: ✅ Foundation/Diploma → 학사 → 석사 (단계별) | Wilson 19년: 석사 = 학사 학위 필수. 고졸 = 학사부터 시작', '{"rule_name": "고졸 + 석사 직접 차단", "condition": "한국 학력 = 고졸 (검정고시/수능/내신) + 호주 석사 Direct 지원", "action": "❌ 석사 Direct 차단", "alternative": "✅ Foundation/Diploma → 학사 → 석사 (단계별)", "wilson_reason": "석사 = 학사 학위 필수. 고졸 = 학사부터 시작", "origin": "윌슨 BLOCK-002 + ChatGPT ABS-03 통합", "priority": "높음"}'::jsonb, '❌ 석사 Direct 차단', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('DIR-03', 'soft', 'category_3_direct_entry_block', '검정고시 + Go8 직접 차단', 'Condition: 한국 학력 = 검정고시 + Go8 Direct 입학 시도 | Action: ⚠️ Go8 8개 학교 Direct = 까다로움 (불가능 가까움) | Alternative: ✅ Foundation 컬리지 (Trinity/Monash College/UNSW Foundation/Eynesbury) → Go8 1학년 | Wilson 19년: 검정고시 = 호주 학교가 한국 정규 고졸로 인정 안 함 = Foundation 안전한 길', '{"rule_name": "검정고시 + Go8 직접 차단", "condition": "한국 학력 = 검정고시 + Go8 Direct 입학 시도", "action": "⚠️ Go8 8개 학교 Direct = 까다로움 (불가능 가까움)", "alternative": "✅ Foundation 컬리지 (Trinity/Monash College/UNSW Foundation/Eynesbury) → Go8 1학년", "wilson_reason": "검정고시 = 호주 학교가 한국 정규 고졸로 인정 안 함 = Foundation 안전한 길", "origin": "윌슨 BLOCK-003 + ChatGPT DIR-03 통합", "priority": "높음"}'::jsonb, '⚠️ Go8 8개 학교 Direct = 까다로움 (불가능 가까움)', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('DIR-04', 'soft', 'category_3_direct_entry_block', '비전공 + Master 차단', 'Condition: 한국 학사 학과 ≠ 호주 Master 전공 (Engineering/IT/Nursing/MSW 등) | Action: ⚠️ Direct 차단 또는 추가 코스 필요 | Alternative: ✅ Graduate Certificate (6개월) → Master / 또는 학부 1년 추가 | Wilson 19년: Engineering/IT/Nursing/MSW 석사 = 학부 전공 이수 필수. 비전공 = 추가 학습 필요. AASW/ACS/AHPRA 등 협회 인증 엄격', '{"rule_name": "비전공 + Master 차단", "condition": "한국 학사 학과 ≠ 호주 Master 전공 (Engineering/IT/Nursing/MSW 등)", "action": "⚠️ Direct 차단 또는 추가 코스 필요", "alternative": "✅ Graduate Certificate (6개월) → Master / 또는 학부 1년 추가", "wilson_reason": "Engineering/IT/Nursing/MSW 석사 = 학부 전공 이수 필수. 비전공 = 추가 학습 필요. AASW/ACS/AHPRA 등 협회 인증 엄격", "origin": "윌슨 BLOCK-004/007/008 + ChatGPT DIR-05/MAJ-IT-01 통합", "priority": "높음"}'::jsonb, '⚠️ Direct 차단 또는 추가 코스 필요', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('DIR-05', 'soft', 'category_3_direct_entry_block', '경력 없음 + MBA 차단', 'Condition: 한국 직장 경력 < 2년 + MBA 지원 | Action: ❌ MBA Direct 차단 (대부분 호주 MBA = 2-3년 경력 必) | Alternative: ✅ Master of Business / Master of Management (경력 X 가능) 또는 Bond MBA | Wilson 19년: MBA = 경력자용. 경력 없음 = MBA 가치 낮고 비싸게 시간 낭비', '{"rule_name": "경력 없음 + MBA 차단", "condition": "한국 직장 경력 < 2년 + MBA 지원", "action": "❌ MBA Direct 차단 (대부분 호주 MBA = 2-3년 경력 必)", "alternative": "✅ Master of Business / Master of Management (경력 X 가능) 또는 Bond MBA", "wilson_reason": "MBA = 경력자용. 경력 없음 = MBA 가치 낮고 비싸게 시간 낭비", "origin": "윌슨 BLOCK-005", "priority": "높음"}'::jsonb, '❌ MBA Direct 차단 (대부분 호주 MBA = 2-3년 경력 必)', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('DIR-06', 'soft', 'category_3_direct_entry_block', 'GPA 2.0 미만 + Go8 석사 차단', 'Condition: 한국 학사 GPA < 2.0/4.5 (= 2.0/4.0) + Go8 석사 지원 | Action: ❌ Go8 석사 Direct 차단 | Alternative: ✅ 비-Go8 석사 또는 Graduate Diploma → 석사 단계별 | Wilson 19년: Go8 석사 입학 = 평균 GPA 3.0+/4.0. 너무 낮으면 입학 거부', '{"rule_name": "GPA 2.0 미만 + Go8 석사 차단", "condition": "한국 학사 GPA < 2.0/4.5 (= 2.0/4.0) + Go8 석사 지원", "action": "❌ Go8 석사 Direct 차단", "alternative": "✅ 비-Go8 석사 또는 Graduate Diploma → 석사 단계별", "wilson_reason": "Go8 석사 입학 = 평균 GPA 3.0+/4.0. 너무 낮으면 입학 거부", "origin": "윌슨 BLOCK-006 + ChatGPT DIR-04 통합", "priority": "높음"}'::jsonb, '❌ Go8 석사 Direct 차단', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('DIR-07', 'soft', 'category_3_direct_entry_block', '학점은행/사이버대 + Go8 차단', 'Condition: 한국 학력 = 학점은행 / 사이버대 / 야간대 졸업 + Go8 지원 | Action: ⚠️ USyd / UMelb / UNSW / Monash 등 = 학위 인정 안 함 (대부분) | Alternative: ✅ 비-Go8 공립대 일부 / 사립대 / Foundation 패스웨이 | Wilson 19년: Go8 = 정규 4년제 한국 대학 학위만 인정. 학점은행 = 학위 인정 학교 별도 확인 必', '{"rule_name": "학점은행/사이버대 + Go8 차단", "condition": "한국 학력 = 학점은행 / 사이버대 / 야간대 졸업 + Go8 지원", "action": "⚠️ USyd / UMelb / UNSW / Monash 등 = 학위 인정 안 함 (대부분)", "alternative": "✅ 비-Go8 공립대 일부 / 사립대 / Foundation 패스웨이", "wilson_reason": "Go8 = 정규 4년제 한국 대학 학위만 인정. 학점은행 = 학위 인정 학교 별도 확인 必", "origin": "윌슨 BLOCK-009", "priority": "높음"}'::jsonb, '⚠️ USyd / UMelb / UNSW / Monash 등 = 학위 인정 안 함 (대부분', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('DIR-08', 'soft', 'category_3_direct_entry_block', 'Year 12만 1년 = 호주 대학 진학 차단', 'Condition: 한국 고2 + 호주 Year 12 1년 = 호주 대학 직진 | Action: ⚠️ ATAR 1년 = 호주 대학 매우 어려움 | Alternative: ✅ Foundation (1년) → 학사 1학년 / 또는 Year 11-12 (2년) → ATAR | Wilson 19년: ATAR = 2년 누적 평가. 1년만 하면 Year 12 시험만으로 평가되어 한국 학생 매우 불리', '{"rule_name": "Year 12만 1년 = 호주 대학 진학 차단", "condition": "한국 고2 + 호주 Year 12 1년 = 호주 대학 직진", "action": "⚠️ ATAR 1년 = 호주 대학 매우 어려움", "alternative": "✅ Foundation (1년) → 학사 1학년 / 또는 Year 11-12 (2년) → ATAR", "wilson_reason": "ATAR = 2년 누적 평가. 1년만 하면 Year 12 시험만으로 평가되어 한국 학생 매우 불리", "origin": "윌슨 BLOCK-018", "priority": "높음"}'::jsonb, '⚠️ ATAR 1년 = 호주 대학 매우 어려움', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('RISK-01', 'soft', 'category_4_high_risk', '워홀 → 전공 변경', 'Condition: 워홀 후 학생비자 전환 + 한국 학력과 다른 전공 선택 | Action: ⚠️ HIGH RISK / 사유서 필수 | Alternative: ✅ 전공 변경 사유 + 워홀 경험 연결 + 커리어 계획 | Wilson 19년: DHA = 워홀 후 무관한 전공 = GS 의심. 워홀 직종 + 새 전공 = 연결성 명확히', '{"rule_name": "워홀 → 전공 변경", "condition": "워홀 후 학생비자 전환 + 한국 학력과 다른 전공 선택", "action": "⚠️ HIGH RISK / 사유서 필수", "alternative": "✅ 전공 변경 사유 + 워홀 경험 연결 + 커리어 계획", "wilson_reason": "DHA = 워홀 후 무관한 전공 = GS 의심. 워홀 직종 + 새 전공 = 연결성 명확히", "origin": "ChatGPT 신규", "priority": "높음"}'::jsonb, '⚠️ HIGH RISK / 사유서 필수', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('RISK-02', 'soft', 'category_4_high_risk', '나이 대비 낮은 과정', 'Condition: 30대+ 학생 + Cert/Diploma 등 낮은 과정 지원 | Action: ⚠️ HIGH RISK / GS 평가 까다로움 | Alternative: ✅ 직업 전환 사유 + PR 경로 명확화 (TAFE 트레이드 = OK) | Wilson 19년: 30대+ = 보통 Master 진학. 낮은 과정 선택 시 = 직업/PR 명확한 사유 必', '{"rule_name": "나이 대비 낮은 과정", "condition": "30대+ 학생 + Cert/Diploma 등 낮은 과정 지원", "action": "⚠️ HIGH RISK / GS 평가 까다로움", "alternative": "✅ 직업 전환 사유 + PR 경로 명확화 (TAFE 트레이드 = OK)", "wilson_reason": "30대+ = 보통 Master 진학. 낮은 과정 선택 시 = 직업/PR 명확한 사유 必", "origin": "ChatGPT RISK-04 + 윌슨 BLOCK-005 통합", "priority": "높음"}'::jsonb, '⚠️ HIGH RISK / GS 평가 까다로움', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('RISK-03', 'soft', 'category_4_high_risk', 'PR + Sydney/Melbourne Metro 차단', 'Condition: PR 목표 + 도시 = Sydney / Melbourne Metro | Action: ❌ Metro = Regional 가산점 0점 = PR 어려움 | Alternative: ✅ Cat 3 DRA: Hobart / Darwin / Cairns / Townsville / Ballarat (+15점 + 추가) / Cat 2 +15: Perth / Adelaide / Gold Coast / Canberra / Newcastle | Wilson 19년: PR 빠른 길 = Regional 가산점 必. Metro = 학벌만 가능 / PR 어려움', '{"rule_name": "PR + Sydney/Melbourne Metro 차단", "condition": "PR 목표 + 도시 = Sydney / Melbourne Metro", "action": "❌ Metro = Regional 가산점 0점 = PR 어려움", "alternative": "✅ Cat 3 DRA: Hobart / Darwin / Cairns / Townsville / Ballarat (+15점 + 추가) / Cat 2 +15: Perth / Adelaide / Gold Coast / Canberra / Newcastle", "wilson_reason": "PR 빠른 길 = Regional 가산점 必. Metro = 학벌만 가능 / PR 어려움", "origin": "윌슨 BLOCK-012 + ChatGPT BUD-03 통합", "priority": "매우 높음 (PR 학생)"}'::jsonb, '❌ Metro = Regional 가산점 0점 = PR 어려움', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('RISK-04', 'soft', 'category_4_high_risk', 'PR 목적 + 트레이드 1.5년 미만', 'Condition: PR 목적 + 트레이드 (Carpenter/Welder/Chef 등) 1.5년 미만 코스 | Action: ❌ 자동 차단 + 2년 패키지 자동 추천 | Alternative: ✅ 2년 패키지 (Cert IV + Diploma 또는 Diploma + Adv Diploma) | Wilson 19년: PR 트레이드 = 2년+ 학업 必 (485 비자 자격). 1.5년 = PR 0% / 시간/돈 낭비', '{"rule_name": "PR 목적 + 트레이드 1.5년 미만", "condition": "PR 목적 + 트레이드 (Carpenter/Welder/Chef 등) 1.5년 미만 코스", "action": "❌ 자동 차단 + 2년 패키지 자동 추천", "alternative": "✅ 2년 패키지 (Cert IV + Diploma 또는 Diploma + Adv Diploma)", "wilson_reason": "PR 트레이드 = 2년+ 학업 必 (485 비자 자격). 1.5년 = PR 0% / 시간/돈 낭비", "origin": "윌슨 BLOCK-020", "priority": "높음"}'::jsonb, '❌ 자동 차단 + 2년 패키지 자동 추천', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('RISK-05', 'soft', 'category_4_high_risk', '검정고시 + 단순 자유 추구 + 부모 의지 0%', 'Condition: 검정고시 학생 + 자퇴 사유 = 단순 자유 + 부모 동기 0% | Action: ⚠️ 또 자퇴 위험 / 호주 가서도 못 적응 | Alternative: ✅ 부모 동시 상담 → 양측 동기 정렬 → 진행 / 또는 1년 유예 | Wilson 19년: 윌슨 19년 = 학생만 자유 추구 + 부모 미지원 = 호주 도착 후 또 중도 포기 多', '{"rule_name": "검정고시 + 단순 자유 추구 + 부모 의지 0%", "condition": "검정고시 학생 + 자퇴 사유 = 단순 자유 + 부모 동기 0%", "action": "⚠️ 또 자퇴 위험 / 호주 가서도 못 적응", "alternative": "✅ 부모 동시 상담 → 양측 동기 정렬 → 진행 / 또는 1년 유예", "wilson_reason": "윌슨 19년 = 학생만 자유 추구 + 부모 미지원 = 호주 도착 후 또 중도 포기 多", "origin": "윌슨 BLOCK-021", "priority": "높음 (A1/A2 페르소나)"}'::jsonb, '⚠️ 또 자퇴 위험 / 호주 가서도 못 적응', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('RISK-06', 'soft', 'category_4_high_risk', '검정고시 + 매우 강한 트라우마 + 큰 도시', 'Condition: 검정고시 학생 + 학교 폭력/우울증 등 강한 트라우마 + Sydney/Melbourne 큰 도시 지원 | Action: ⚠️ 재발 방지 위해 매칭 전환 | Alternative: ✅ Adelaide/Hobart 작은 도시 + 한국 학생 < 5% + 케어 좋은 학교 (Foundation) | Wilson 19년: 윌슨 19년 = 트라우마 학생 큰 도시 = 또 압박/우울증 재발 위험. 작은 도시 = 회복 시간', '{"rule_name": "검정고시 + 매우 강한 트라우마 + 큰 도시", "condition": "검정고시 학생 + 학교 폭력/우울증 등 강한 트라우마 + Sydney/Melbourne 큰 도시 지원", "action": "⚠️ 재발 방지 위해 매칭 전환", "alternative": "✅ Adelaide/Hobart 작은 도시 + 한국 학생 < 5% + 케어 좋은 학교 (Foundation)", "wilson_reason": "윌슨 19년 = 트라우마 학생 큰 도시 = 또 압박/우울증 재발 위험. 작은 도시 = 회복 시간", "origin": "윌슨 BLOCK-022", "priority": "높음 (A1/A2 페르소나)"}'::jsonb, '⚠️ 재발 방지 위해 매칭 전환', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('RISK-07', 'soft', 'category_4_high_risk', '한국 학생 30%+ 학교 추천 차단 (Wilson 강세)', 'Condition: 추천하려는 학교 한국 학생 비율 ≥ 30% | Action: ❌ 한국 학생 30%+ 학교 추천 차단 | Alternative: ✅ 한국 학생 < 15% 학교 우선 / Cat 2-3 도시 우선 (Adelaide/Darwin/Hobart 한국인 < 5%) | Wilson 19년: 윌슨 19년 = 한국 학생 多 학교 = 한국어 사용 多 = 영어 향상 X = 호주 대학 진학 페일 多. Strathfield/Burwood/Chatswood/Box Hill/Glen Waverley = 회피', '{"rule_name": "한국 학생 30%+ 학교 추천 차단 (Wilson 강세)", "condition": "추천하려는 학교 한국 학생 비율 ≥ 30%", "action": "❌ 한국 학생 30%+ 학교 추천 차단", "alternative": "✅ 한국 학생 < 15% 학교 우선 / Cat 2-3 도시 우선 (Adelaide/Darwin/Hobart 한국인 < 5%)", "wilson_reason": "윌슨 19년 = 한국 학생 多 학교 = 한국어 사용 多 = 영어 향상 X = 호주 대학 진학 페일 多. Strathfield/Burwood/Chatswood/Box Hill/Glen Waverley = 회피", "origin": "윌슨 BLOCK-019", "priority": "Wilson 강세"}'::jsonb, '❌ 한국 학생 30%+ 학교 추천 차단', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('RISK-08', 'hard', 'category_4_high_risk', '18세 미만 + 부모 동반 X + 영어 X', 'Condition: 학생 14-17세 + 부모/Guardian X + IELTS 5.0 미만 | Action: ❌ 호주 단독 유학 차단 | Alternative: ✅ 옵션 A: 부모 동반 (590 Guardian Visa) / 옵션 B: 어학원 6개월 + 부모 단기 동반 + 적응 후 단독 | Wilson 19년: Wilson 19년 = 14-17세 + 부모 동반 X + 영어 X = 학교 적응 매우 어려움 / Welfare 위반 多 / 비자 취소 위험', '{"rule_name": "18세 미만 + 부모 동반 X + 영어 X", "condition": "학생 14-17세 + 부모/Guardian X + IELTS 5.0 미만", "action": "❌ 호주 단독 유학 차단", "alternative": "✅ 옵션 A: 부모 동반 (590 Guardian Visa) / 옵션 B: 어학원 6개월 + 부모 단기 동반 + 적응 후 단독", "wilson_reason": "Wilson 19년 = 14-17세 + 부모 동반 X + 영어 X = 학교 적응 매우 어려움 / Welfare 위반 多 / 비자 취소 위험", "origin": "윌슨 BLOCK-017", "priority": "절대 (A5 페르소나)"}'::jsonb, '❌ 호주 단독 유학 차단', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('RISK-09', 'soft', 'category_4_high_risk', '35세+ + 영어 부족 + 자격 없음 (B4 핵심)', 'Condition: B4 직장인 + 35세+ + IELTS < 6.0 + PR 자격 직업 X | Action: ⚠️ HIGH RISK / PR 매우 어려움 / 시간/돈 손실 위험 | Alternative: ✅ 영어 점수 우선 보강 (IELTS 7.0+ Proficient 10점) / 또는 491 지방 후원 (Cat 3) / 또는 직업 전환 (TAFE 트레이드) | Wilson 19년: B4 페르소나 차단룰 = 윌슨 19년 = 35세+ 영어 부족 = PR 점수 부족 + 비자 자격 부족 = PR 거의 불가능. 영어/직업 보강 必', '{"rule_name": "35세+ + 영어 부족 + 자격 없음 (B4 핵심)", "condition": "B4 직장인 + 35세+ + IELTS < 6.0 + PR 자격 직업 X", "action": "⚠️ HIGH RISK / PR 매우 어려움 / 시간/돈 손실 위험", "alternative": "✅ 영어 점수 우선 보강 (IELTS 7.0+ Proficient 10점) / 또는 491 지방 후원 (Cat 3) / 또는 직업 전환 (TAFE 트레이드)", "wilson_reason": "B4 페르소나 차단룰 = 윌슨 19년 = 35세+ 영어 부족 = PR 점수 부족 + 비자 자격 부족 = PR 거의 불가능. 영어/직업 보강 必", "origin": "윌슨 B4 페르소나 차단룰 정식 등재 (2026-04-29)", "priority": "높음 (B4 핵심)"}'::jsonb, '⚠️ HIGH RISK / PR 매우 어려움 / 시간/돈 손실 위험', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('BUD-01', 'soft', 'category_5_budget', '예산 부족 + Go8 학사 차단', 'Condition: 연간 예산 < $30,000 + Go8 학사 지원 | Action: ❌ Go8 학사 = 평균 $40-60K/년 = 4년 = $160-240K = 부담 과도 | Alternative: ✅ Cat 3 DRA Regional (Federation/CDU/UTAS/JCU/Avondale) = $24-35K + PR | Wilson 19년: 예산 부족 = 부모 지원 끊김 → 중도 포기 → 귀국 (윌슨 19년 자주 본 실패)', '{"rule_name": "예산 부족 + Go8 학사 차단", "condition": "연간 예산 < $30,000 + Go8 학사 지원", "action": "❌ Go8 학사 = 평균 $40-60K/년 = 4년 = $160-240K = 부담 과도", "alternative": "✅ Cat 3 DRA Regional (Federation/CDU/UTAS/JCU/Avondale) = $24-35K + PR", "wilson_reason": "예산 부족 = 부모 지원 끊김 → 중도 포기 → 귀국 (윌슨 19년 자주 본 실패)", "origin": "윌슨 BLOCK-011 + ChatGPT BUD-01 통합", "priority": "높음"}'::jsonb, '❌ Go8 학사 = 평균 $40-60K/년 = 4년 = $160-240K = 부담 과도', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('BUD-02', 'hard', 'category_5_budget', '생활비 증빙 없음', 'Condition: 학비 외 생활비 12개월 증빙 불가 (2026 기준 = $29,710/년) | Action: ❌ 학생비자 신청 자체 불가 | Alternative: ✅ 부모 후원 증빙 + 은행 잔고 + 12개월 생활비 마련 | Wilson 19년: DHA 2026 = 학생비자 = 학비 + 생활비 $29,710 + 항공료 $2,500 = 모두 증빙 필수. 미증빙 = 비자 거절', '{"rule_name": "생활비 증빙 없음", "condition": "학비 외 생활비 12개월 증빙 불가 (2026 기준 = $29,710/년)", "action": "❌ 학생비자 신청 자체 불가", "alternative": "✅ 부모 후원 증빙 + 은행 잔고 + 12개월 생활비 마련", "wilson_reason": "DHA 2026 = 학생비자 = 학비 + 생활비 $29,710 + 항공료 $2,500 = 모두 증빙 필수. 미증빙 = 비자 거절", "origin": "ChatGPT 신규 2026 강화", "priority": "절대"}'::jsonb, '❌ 학생비자 신청 자체 불가', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('BLOCK-032', 'soft', 'category_7_2026_5step_logic_logic', 'BLOCK-032', 'Action: 추천 학교/코스가 CRICOS 등록인지 확인', '{"step": 1, "name": "CRICOS 체크", "action": "추천 학교/코스가 CRICOS 등록인지 확인", "fail_action": "→ 즉시 제외 (ABS-01)"}'::jsonb, '추천 학교/코스가 CRICOS 등록인지 확인', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('BLOCK-033', 'soft', 'category_7_2026_5step_logic_logic', 'BLOCK-033', 'Action: 전공 이유 + 학업 흐름 + 커리어 연결 모두 명확한지 확인', '{"step": 2, "name": "GS 체크 (가장 중요)", "action": "전공 이유 + 학업 흐름 + 커리어 연결 모두 명확한지 확인", "fail_action": "→ GS-01~07 적용 / 사유서 보강 필수"}'::jsonb, '전공 이유 + 학업 흐름 + 커리어 연결 모두 명확한지 확인', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('BLOCK-034', 'soft', 'category_7_2026_5step_logic_logic', 'BLOCK-034', 'Action: 영어 점수 + 학력 충분한지 확인', '{"step": 3, "name": "영어 / 학력 체크", "action": "영어 점수 + 학력 충분한지 확인", "fail_action": "→ DIR-01~08 적용 / 루트 변경 (어학원/Foundation)"}'::jsonb, '영어 점수 + 학력 충분한지 확인', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('BLOCK-035', 'soft', 'category_7_2026_5step_logic_logic', 'BLOCK-035', 'Action: 학비 + 생활비 ($29,710) + 항공료 ($2,500) 모두 증빙 가능한지 확인', '{"step": 4, "name": "재정 체크", "action": "학비 + 생활비 ($29,710) + 항공료 ($2,500) 모두 증빙 가능한지 확인", "fail_action": "→ BUD-01~02 적용 / 가성비 학교 추천"}'::jsonb, '학비 + 생활비 ($29,710) + 항공료 ($2,500) 모두 증빙 가능한지 확인', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO blocking_rules (rule_id, severity, category, title, description, conditions, action, active) VALUES ('BLOCK-036', 'soft', 'category_7_2026_5step_logic_logic', 'BLOCK-036', 'Action: Wilson 19년 = 영어 점수만이 아닌 학업 적응 자신감 점검 + 학생/학부모 선택 존중', '{"step": 5, "name": "EAP / 안전망 체크 (Wilson 추가)", "action": "Wilson 19년 = 영어 점수만이 아닌 학업 적응 자신감 점검 + 학생/학부모 선택 존중", "fail_action": "→ EAP 권장 (시험 ≠ 실전 / 윌슨 명언: 영어 있어도 EAP 같은 거 해봐라)", "wilson_addition": true}'::jsonb, 'Wilson 19년 = 영어 점수만이 아닌 학업 적응 자신감 점검 + 학생/학부모 선택 존', TRUE) ON CONFLICT (rule_id) DO NOTHING;
INSERT INTO wilson_alerts_rules (alert_id, title, wilson_quote, principle, wilson_truth, applies_to, marketing_application, conditions, active) VALUES ('ibt_renaming', 'ibt renaming', '✅ 2026-04-28 검증 완료 / IBT 형식 명칭 = 모두 새 명칭 사용', NULL, NULL, NULL, NULL, '{}'::jsonb, TRUE) ON CONFLICT (alert_id) DO NOTHING;
